import {
    Button as GluestackButton,
    ButtonIcon,
    ButtonSpinner,
    ButtonText as GSButtonText,
    ResponsiveElement,
    style,
    useSeparator
} from '@lmb-it/kitsconcertomobile';
import type { IButtonProps, IconName } from '@lmb-it/kitsconcerto-types';
import { useButton } from './useButton';
import React, { type ElementType, isValidElement, type ReactElement } from "react";
import { IconMap } from '../../assets/Icons';
import {useLanguage, useComponentDefaults} from "@lmb-it/kitsconcerto/hooks";
import {useSeverityColors} from '../../hooks/useSeverityColors';
const TEXT_STYLE_KEYS = new Set([
    'color', 'fontSize', 'fontFamily', 'fontWeight',
    'letterSpacing', 'lineHeight', 'textAlign',
    'textTransform', 'fontStyle', 'textDecorationLine',
]);

function resolveIcon(icon: unknown): ElementType | ReactElement | undefined {
    if (!icon) return undefined;
    if (isValidElement(icon)) return icon as ReactElement;
    if (typeof icon === 'function') return icon as ElementType;
    if (typeof icon === 'string') {
        const piMatches = icon.match(/pi-([a-z-]+)/g);
        const iconName = piMatches
            ? (piMatches[piMatches.length - 1]!.replace('pi-', '') as IconName)
            : (icon as IconName);
        return IconMap[iconName];
    }
    return undefined;
}

export function Button(rawProps: IButtonProps<IconName | string | ElementType | ReactElement>) {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Button', rawProps);
    const { children, label, isLoadingText, severity = 'primary', size = 'md', loading, outlined, icon, iconPos = 'left' } = props;
    const { handlers, isDisabled, _nativeProps } = useButton(props);
    const { cssProps, nativeProps } = useSeparator<Record<any, any>>(_nativeProps);
    const {t} = useLanguage()

    const brandColors = useSeverityColors((severity as any) ?? 'secondary');
    const isBrand = severity === 'brand';

    const gluestackVariant = outlined ? 'outline' : 'solid';
    const SEVERITY_TO_ACTION: Record<string, string> = {
        primary: 'primary',
        danger: 'negative',
        success: 'positive',
        secondary: 'secondary',
        info: 'primary',
        warning: 'negative',
        help: 'secondary',
        brand: 'primary',
    };
    const action = SEVERITY_TO_ACTION[severity] ?? 'primary';

    const resolvedIcon = resolveIcon(icon);

    const resolvedLabel =
        typeof children === "string"
            ? children
            : loading && isLoadingText
                ? isLoadingText
                : t(label ?? "");

    const iconSizesMap = {
        '2xs':'2xs',
        'xs':'xs',
        'sm':'md',
        'md':'md',
        'lg':'lg',
        'xl':'lg',
    }
    // Merge: theme (lowest) < elementStyles.root (middle) < inline cssProps (highest)
    const mergedCssProps = {...themeStyle, ...(elementStyles.root || {}), ...cssProps};

    // Extract text-related styles from merged cssProps so ButtonText can inherit them
    const computedStyles = style(mergedCssProps) as Record<string, any>;
    const textStyles = Object.fromEntries(
        Object.entries(computedStyles).filter(([k]) => TEXT_STYLE_KEYS.has(k))
    );

    // Extract borderRadius styles to pass through to GluestackButton
    const BORDER_RADIUS_KEYS = new Set([
        'borderRadius', 'borderTopLeftRadius', 'borderTopRightRadius',
        'borderBottomLeftRadius', 'borderBottomRightRadius',
    ]);
    const borderRadiusStyles = Object.fromEntries(
        Object.entries(computedStyles).filter(([k]) => BORDER_RADIUS_KEYS.has(k))
    );

    // Brand severity: override Gluestack colors with theme brand colors
    const brandButtonStyle: Record<string, any> = {};
    if (isBrand) {
        if (outlined) {
            brandButtonStyle.borderColor = brandColors.solid;
            brandButtonStyle.backgroundColor = 'transparent';
            textStyles.color = brandColors.solid;
        } else {
            brandButtonStyle.backgroundColor = brandColors.solid;
            brandButtonStyle.borderColor = brandColors.solid;
            textStyles.color = '#FFFFFF';
        }
    }

    const gluestackStyle = {
        ...borderRadiusStyles,
        ...brandButtonStyle,
        justifyContent: 'center' as const,
        alignItems: 'center' as const,
        flexDirection: 'row' as const,
    };

    return (
        <ResponsiveElement
            as="Box"
            additionalStyles={{alignSelf: 'flex-start', overflow: 'hidden'}}
            cssProps={mergedCssProps}
            nativeProps={{}}
        >
            <GluestackButton
                variant={gluestackVariant}
                action={action}
                size={size}
                isDisabled={isDisabled || loading}
                //@ts-ignore
                onPress={handlers.onClick}
                onPressIn={handlers.onPressIn}
                onPressOut={handlers.onPressOut}
                testID={props.testID}
                {...nativeProps}
                style={Object.keys(gluestackStyle).length ? gluestackStyle : undefined}
            >
                {isValidElement(resolvedIcon) && iconPos === 'left' && resolvedIcon}
                {/*@ts-ignore*/}
                {resolvedIcon && !isValidElement(resolvedIcon) && iconPos === 'left' && <ButtonIcon as={resolvedIcon as ElementType} size={iconSizesMap[size]}/>}
                {loading && <ButtonSpinner color={isBrand ? '#FFFFFF' : 'gray'}/>}

                {(children || label) && (
                    <GSButtonText style={Object.keys(textStyles).length ? textStyles : undefined}>
                        {resolvedLabel}
                    </GSButtonText>
                )}

                {isValidElement(resolvedIcon) && iconPos === 'right' && resolvedIcon}
                {/*@ts-ignore*/}
                {resolvedIcon && !isValidElement(resolvedIcon) && iconPos === 'right' && <ButtonIcon as={resolvedIcon as ElementType} size={iconSizesMap[size]}/>}
            </GluestackButton>
        </ResponsiveElement>
    );
}

export default Button;
